  "inlineSchema": "// =============================================================\n// GovCon Advisory Intelligence Platform\n// Prisma Schema - Multi-Tenant SaaS Data Model\n// =============================================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// =============================================================\n// TENANT LAYER\n// =============================================================\n\nmodel ConsultingFirm {\n  id           String  @id @default(uuid())\n  name         String\n  contactEmail String  @unique\n  isActive     Boolean @default(true)\n\n  // Penalty configuration\n  flatLateFee    Float? // Fixed dollar penalty for late submissions\n  penaltyPercent Float? // Percentage of estimated value for late submissions\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  users              User[]\n  clientCompanies    ClientCompany[]\n  opportunities      Opportunity[]\n  financialPenalties FinancialPenalty[]\n\n  @@map(\"consulting_firms\")\n}\n\nmodel User {\n  id               String   @id @default(uuid())\n  consultingFirmId String\n  email            String   @unique\n  passwordHash     String\n  firstName        String\n  lastName         String\n  role             UserRole @default(CONSULTANT)\n  isActive         Boolean  @default(true)\n\n  lastLoginAt DateTime?\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n\n  // Relations\n  consultingFirm    ConsultingFirm     @relation(fields: [consultingFirmId], references: [id], onDelete: Cascade)\n  submissionRecords SubmissionRecord[]\n\n  @@index([consultingFirmId])\n  @@map(\"users\")\n}\n\nenum UserRole {\n  ADMIN\n  CONSULTANT\n}\n\n// =============================================================\n// CLIENT LAYER\n// =============================================================\n\nmodel ClientCompany {\n  id               String   @id @default(uuid())\n  consultingFirmId String\n  name             String\n  cage             String?\n  uei              String?\n  naicsCodes       String[] // Registered NAICS codes for this contractor\n  sdvosb           Boolean  @default(false)\n  wosb             Boolean  @default(false)\n  hubzone          Boolean  @default(false)\n  smallBusiness    Boolean  @default(true)\n  isActive         Boolean  @default(true)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  consultingFirm     ConsultingFirm     @relation(fields: [consultingFirmId], references: [id], onDelete: Cascade)\n  submissionRecords  SubmissionRecord[]\n  performanceStats   PerformanceStats?\n  financialPenalties FinancialPenalty[]\n\n  @@index([consultingFirmId])\n  @@map(\"client_companies\")\n}\n\n// =============================================================\n// OPPORTUNITY LAYER\n// =============================================================\n\nmodel Opportunity {\n  id               String @id @default(uuid())\n  consultingFirmId String\n\n  // SAM.gov fields\n  samNoticeId      String?        @unique\n  title            String\n  agency           String\n  subagency        String?\n  office           String?\n  naicsCode        String\n  naicsDescription String?\n  setAsideType     SetAsideType   @default(NONE)\n  marketCategory   MarketCategory @default(SUPPLIES)\n\n  // Financials\n  estimatedValue    Float?\n  estimatedValueMin Float?\n  estimatedValueMax Float?\n\n  // Dates\n  postedDate       DateTime?\n  responseDeadline DateTime\n  archiveDate      DateTime?\n\n  // Location\n  placeOfPerformance String?\n\n  // Source data\n  sourceUrl   String?\n  description String? @db.Text\n  attachments Json?\n\n  // Computed fields (updated by scoring engine)\n  probabilityScore Float? @default(0)\n  expectedValue    Float? @default(0)\n\n  // Status\n  status OpportunityStatus @default(ACTIVE)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  consultingFirm    ConsultingFirm     @relation(fields: [consultingFirmId], references: [id], onDelete: Cascade)\n  submissionRecords SubmissionRecord[]\n\n  @@index([consultingFirmId])\n  @@index([naicsCode])\n  @@index([agency])\n  @@index([responseDeadline])\n  @@index([probabilityScore])\n  @@map(\"opportunities\")\n}\n\nenum SetAsideType {\n  NONE\n  SMALL_BUSINESS\n  SDVOSB\n  WOSB\n  HUBZONE\n  EightA\n  TOTAL_SMALL_BUSINESS\n}\n\nenum MarketCategory {\n  SERVICES\n  SUPPLIES\n  CONSTRUCTION\n  IT\n  RESEARCH\n  MEDICAL\n  LOGISTICS\n  OTHER\n}\n\nenum OpportunityStatus {\n  ACTIVE\n  AWARDED\n  CANCELLED\n  ARCHIVED\n}\n\n// =============================================================\n// SUBMISSION TRACKING\n// =============================================================\n\nmodel SubmissionRecord {\n  id               String @id @default(uuid())\n  consultingFirmId String\n  clientCompanyId  String\n  opportunityId    String\n  submittedById    String\n\n  submittedAt   DateTime\n  wasOnTime     Boolean\n  penaltyAmount Float    @default(0)\n\n  notes String? @db.Text\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  clientCompany    ClientCompany     @relation(fields: [clientCompanyId], references: [id], onDelete: Cascade)\n  opportunity      Opportunity       @relation(fields: [opportunityId], references: [id], onDelete: Cascade)\n  submittedBy      User              @relation(fields: [submittedById], references: [id])\n  financialPenalty FinancialPenalty?\n\n  @@index([clientCompanyId])\n  @@index([opportunityId])\n  @@index([consultingFirmId])\n  @@map(\"submission_records\")\n}\n\n// =============================================================\n// FINANCIAL PENALTIES\n// =============================================================\n\nmodel FinancialPenalty {\n  id                 String @id @default(uuid())\n  consultingFirmId   String\n  clientCompanyId    String\n  submissionRecordId String @unique\n\n  penaltyType      PenaltyType\n  amount           Float\n  calculationBasis String // Human-readable explanation\n  isPaid           Boolean     @default(false)\n  paidAt           DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  consultingFirm   ConsultingFirm   @relation(fields: [consultingFirmId], references: [id], onDelete: Cascade)\n  clientCompany    ClientCompany    @relation(fields: [clientCompanyId], references: [id], onDelete: Cascade)\n  submissionRecord SubmissionRecord @relation(fields: [submissionRecordId], references: [id])\n\n  @@index([consultingFirmId])\n  @@index([clientCompanyId])\n  @@map(\"financial_penalties\")\n}\n\nenum PenaltyType {\n  FLAT_FEE\n  PERCENTAGE\n}\n\n// =============================================================\n// PERFORMANCE STATISTICS\n// =============================================================\n\nmodel PerformanceStats {\n  id              String @id @default(uuid())\n  clientCompanyId String @unique\n\n  totalOpportunities Int   @default(0)\n  totalSubmissions   Int   @default(0)\n  submissionsOnTime  Int   @default(0)\n  submissionsLate    Int   @default(0)\n  completionRate     Float @default(0) // submissionsOnTime / totalSubmissions\n  totalPenalties     Float @default(0)\n\n  lastCalculatedAt DateTime @default(now())\n  updatedAt        DateTime @updatedAt\n\n  // Relations\n  clientCompany ClientCompany @relation(fields: [clientCompanyId], references: [id], onDelete: Cascade)\n\n  @@map(\"performance_stats\")\n}\n",
